package logger

import (
	"fmt"
	"io"
	"log/slog"
	"os"
)

type Level int

const (
	DEBUG Level = iota
	INFO
	WARN
	ERROR
)

func levelToSlog(l Level) slog.Level {
	switch l {
	case DEBUG:
		return slog.LevelDebug
	case WARN:
		return slog.LevelWarn
	case ERROR:
		return slog.LevelError
	default:
		return slog.LevelInfo
	}
}

type Logger struct {
	slog *slog.Logger
}

func New(level Level) *Logger {
	return NewWithWriter(level, os.Stderr)
}

func NewWithWriter(level Level, w io.Writer) *Logger {
	opts := &slog.HandlerOptions{
		Level: levelToSlog(level),
		ReplaceAttr: func(groups []string, a slog.Attr) slog.Attr {
			if a.Key == slog.TimeKey {
				a.Value = slog.StringValue(a.Value.Time().Format("2006-01-02T15:04:05"))
			}
			if a.Key == slog.LevelKey {
				a.Value = slog.StringValue(fmt.Sprintf("[%s]", a.Value.String()))
			}
			return a
		},
	}
	handler := slog.NewTextHandler(w, opts)
	return &Logger{slog: slog.New(handler)}
}

func (l *Logger) Debug(msg string, args ...any) {
	l.slog.Debug(fmt.Sprintf(msg, args...))
}
func (l *Logger) Info(msg string, args ...any) {
	l.slog.Info(fmt.Sprintf(msg, args...))
}
func (l *Logger) Warn(msg string, args ...any) {
	l.slog.Warn(fmt.Sprintf(msg, args...))
}
func (l *Logger) Error(msg string, args ...any) {
	l.slog.Error(fmt.Sprintf(msg, args...))
}

package logger

import (
	"bytes"
	"strings"
	"testing"
)

func TestInfoLogged(t *testing.T) {
	var buf bytes.Buffer
	l := NewWithWriter(INFO, &buf)
	l.Info("server started on port %d", 8080)
	output := buf.String()
	if !strings.Contains(output, "[INFO]") {
		t.Errorf("expected [INFO] in output, got: %s", output)
	}
	if !strings.Contains(output, "server started on port 8080") {
		t.Errorf("expected message in output, got: %s", output)
	}
}

func TestDebugFiltered(t *testing.T) {
	var buf bytes.Buffer
	l := NewWithWriter(INFO, &buf)
	l.Debug("this should not appear")
	if buf.Len() != 0 {
		t.Errorf("expected empty output for filtered debug, got: %s", buf.String())
	}
}

func TestWarnLogged(t *testing.T) {
	var buf bytes.Buffer
	l := NewWithWriter(DEBUG, &buf)
	l.Warn("disk usage at %d%%", 90)
	output := buf.String()
	if !strings.Contains(output, "[WARN]") {
		t.Errorf("expected [WARN] in output, got: %s", output)
	}
}
